static common_chat_params common_chat_params_init_mistral_instruct_v3(
        const common_chat_template & tmpl,
        const autoparser::generation_params & inputs) {
    common_chat_params data;
    data.format = COMMON_CHAT_FORMAT_CONTENT_ONLY;

    // Collect system prompt to prepend to the first user message
    std::string system_prompt;
    for (const auto & msg : inputs.messages) {
        if (msg.value("role", "") == "system") {
            system_prompt = msg.value("content", "");
            break;
        }
    }

    bool first_user = true;
    std::string prompt = tmpl.bos_token();

    for (const auto & msg : inputs.messages) {
        const std::string role    = msg.value("role", "");
        const std::string content = msg.value("content", "");

        if (role == "system") {
            continue;  // handled via prepend to first user message
        } else if (role == "user") {
            std::string user_content;
            if (first_user && !system_prompt.empty()) {
                user_content = system_prompt + "\n" + content;
            } else {
                user_content = content;
            }
            first_user = false;
            prompt += "[INST] " + user_content + " [/INST]";
        } else if (role == "assistant") {
            prompt += " " + content + "</s>";
        }
    }

    data.prompt = prompt;
    return data;
}

